10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_YEARS_THRESHOLD = 2;
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	const PROCESSING_FEE = 5;
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_BASE = 60;
20	
21	const baseForType = (type: string, count: number): number => {
22	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
23	    return COMPONENT_BLOCK_BASE;
24	  }
25	  return count * BASE_PREMIUMS[type];
26	};
