28	export const runScenario = (scenario: any): unknown => {
29	  const items = scenario.steps[0].items;
30	  const countsByType = new Map<string, number>();
31	  for (const item of items) {
32	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
33	  }
34	  let itemBasesSum = 0;
35	  for (const [type, count] of countsByType) {
36	    itemBasesSum += baseForType(type, count);
37	  }
38	  let itemSurcharges = 0;
39	  for (const item of items) {
40	    const itemBase = BASE_PREMIUMS[item.type];
41	    if (item.cursed) {
42	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
43	    }
44	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
45	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
46	    }
47	  }
48	  const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
49	    ? itemBasesSum * LOYALTY_DISCOUNT_RATE
50	    : 0;
51	  const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount + itemSurcharges;
52	  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
53	  return { results: [{ premium }] };
54	};
